from dataclasses import dataclass
from autogen_core import BaseAgent, MessageContext, AgentId
from autogen_core import SingleThreadedAgentRuntime

@dataclass
class TextMessage:
    content: str

@dataclass
class SummaryRequest:
    text: str

class SummarizerAgent(BaseAgent):
    @property
    def produced_message_types(self):
        return [TextMessage]

    async def handle_message(self, message, ctx: MessageContext):
        if isinstance(message, TextMessage):
            # Echo back an acknowledgement
            return TextMessage(content=f"Received: {message.content[:50]}...")
        if isinstance(message, SummaryRequest):
            # Simulate summarisation
            words = message.text.split()
            summary = " ".join(words[:10]) + "..."
            return TextMessage(content=f"Summary: {summary}")
        return None

import asyncio
from dataclasses import dataclass
from autogen_core import (
    BaseAgent, MessageContext, AgentId,
    SingleThreadedAgentRuntime, TopicId, TypeSubscription,
)

@dataclass
class NewsItem:
    headline: str

class NewsLogger(BaseAgent):
    @property
    def produced_message_types(self):
        return []

    async def handle_message(self, message, ctx: MessageContext):
        if isinstance(message, NewsItem):
            print(f"[NewsLogger] {message.headline}")

async def main():
    runtime = SingleThreadedAgentRuntime()

    await NewsLogger.register(runtime, type="news_logger",
        factory=lambda: NewsLogger("news_logger", runtime))

    # Subscribe the agent to the "news" topic
    await runtime.add_subscription(
        TypeSubscription(topic_type="news", agent_type="news_logger")
    )

    runtime.start()

    # Publish to the topic — all subscribers receive the message
    news_topic = TopicId(type="news", source="default")
    await runtime.publish_message(
        NewsItem(headline="AutoGen 0.4 released with new Core API"),
        topic_id=news_topic,
    )

    await runtime.stop_when_idle()

asyncio.run(main())

import asyncio
from autogen_core import BaseAgent, MessageContext, CancellationToken
from dataclasses import dataclass

@dataclass
class LongTask:
    steps: int

class CancellableAgent(BaseAgent):
    @property
    def produced_message_types(self):
        return []

    async def handle_message(self, message, ctx: MessageContext):
        if isinstance(message, LongTask):
            for i in range(message.steps):
                if ctx.cancellation_token.is_cancelled():
                    print(f"Task cancelled at step {i}")
                    return None
                await asyncio.sleep(0.1)   # simulate work
                print(f"Step {i + 1} done")
            print("Task complete")
        return None

from autogen_core import BaseAgent, MessageContext, message_handler
from dataclasses import dataclass

@dataclass
class GreetRequest:
    name: str

@dataclass
class Farewell:
    name: str

class GreeterAgent(BaseAgent):
    @property
    def produced_message_types(self):
        return [TextMessage]

    @message_handler
    async def on_greet(self, message: GreetRequest, ctx: MessageContext) -> TextMessage:
        return TextMessage(content=f"Hello, {message.name}!")

    @message_handler
    async def on_farewell(self, message: Farewell, ctx: MessageContext) -> TextMessage:
        return TextMessage(content=f"Goodbye, {message.name}!")

from autogen_core import BaseAgent, MessageContext
from dataclasses import dataclass

@dataclass
class CountMessage:
    value: int

class CounterAgent(BaseAgent):
    def __init__(self, name, runtime):
        super().__init__(name, runtime)
        self._total = 0

    @property
    def produced_message_types(self):
        return [TextMessage]

    async def handle_message(self, message, ctx: MessageContext):
        if isinstance(message, CountMessage):
            self._total += message.value
            return TextMessage(content=f"Total: {self._total}")

    async def save_state(self) -> dict:
        return {"total": self._total}

    async def load_state(self, state: dict) -> None:
        self._total = state.get("total", 0)

