from autogen_core import BaseAgent, MessageContext, Interceptor

class LoggingInterceptor(Interceptor):
    async def on_send(self, message, recipient, sender, cancellation_token):
        print(f"[send] {type(message).__name__} -> {recipient}")
        return await super().on_send(message, recipient, sender, cancellation_token)

    async def on_publish(self, message, topic_id, sender, cancellation_token):
        print(f"[publish] {type(message).__name__} -> topic:{topic_id.type}")
        return await super().on_publish(message, topic_id, sender, cancellation_token)

# Register on the runtime before starting
runtime = SingleThreadedAgentRuntime(interceptors=[LoggingInterceptor()])
